比赛链接 RT。这十分恶毒的Microsoft Defender在我使用美丽的Dev-c++和Code::Blocks时疯狂地弹弹窗让我扫描病毒威胁，又由于洛谷在线IDE的格式非常不自动化（指tab要自己tab）因此是我罚时+=5*5min，(╯▔皿▔)╯。 赛时没做出来的会全码写注释 题解A. Past ABCs依旧非常简单，不多说了放代码。 1234567891011121314151617181920212223242526#include&lt;bits/stdc++.h&gt;using namespace std;string s; int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;s; if(s[0]=='A'&amp;&amp;s[1]=='B'&amp;&amp;s[2]=='c') { int t=(s[3]-'0')*100+(s[4]-'0')*10+s[5]-'0'; if(t&gt;=1&amp;&amp;t&lt;350&amp;&amp;t!=316) { cout&lt;&lt;&quot;Yes
&quot;; return 0; } } cout&lt;&lt;&quot;No
&quot;; return 0;} B. Dentist Aoki这个题面真的好癫qwq 按题目模拟就行了没有什么思维含量，但是身为一名蒟蒻，还是交了一遍罚时，原因：没有本地运行代码导致for循环的起始写错了。其实可以用来熟悉bitset的使用（？），遂放一篇bitset的代码 1234567891011121314151617181920212223#include&lt;bits/stdc++.h&gt;using namespace std;int n,q;bitset&lt;1005&gt; b;int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;q; for(int i=0;i&lt;q;i++) { int t; cin&gt;&gt;t; b.flip(t); } cout&lt;&lt;n-b.count()&lt;&lt;&quot;
&quot;; //如果在一开始将bitset初始化为全1，就输出b.count() return 0;} C. Sort 好了，就是这道令我罚时+=4的题力！（蠢蠢的很安心 四发都错在没有将swap了之后的id更改，谁能想到atcoder给的样例一个都查不出来（气 非常直白，存一下每个 $a_i$ 的索引，再遍历，如果 $a_i≠i$ 那么就把 $a_i$ 和 $a$ 中值为 $i$ 的元素交换，然后用vector存即可。 123456789101112131415161718192021222324252627282930313233#include&lt;bits/stdc++.h&gt;using namespace std;int n;int a[200005],id[200005];vector&lt;pair&lt;int,int&gt; &gt; s;int main(){ cin&gt;&gt;n ; for(int i=1;i&lt;=n;i++) { cin&gt;&gt;a[i]; id[a[i]]=i; } for(int i=1;i&lt;=n;i++) { if(a[i]!=i) { swap(a[i],a[id[i]]); s.push_back({i,id[i]}); id[a[id[i]]]=id[i]; } } cout&lt;&lt;s.size()&lt;&lt;&quot;
&quot; ; for(int i=0;i&lt;s.size();i++) { cout&lt;&lt;s[i].first&lt;&lt;&quot; &quot;&lt;&lt;s[i].second&lt;&lt;&quot;
&quot;; } return 0 ;} D. New Friends某位zhy同学没有开龙龙导致WA掉，让我们恭喜他 就是让每一个连通图都变成完全图，所以使用 冰茶几 并查集维护，求出把所有图变成完全图之后的总边数，再减掉原有的变数即可。 1234567891011121314151617181920212223242526272829303132333435363738394041424344#include&lt;bits/stdc++.h&gt;using namespace std;long long n,m;long long par[200005],cnt[200005];long long ans;long long findf(long long x){ return (par[x]==x)?x:par[x]=findf(par[x]);}int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;m; for(long long i=1;i&lt;=n;i++) { par[i]=i; } for(long long i=0;i&lt;m;i++) { long long a,b; cin&gt;&gt;a&gt;&gt;b; par[findf(a)]=findf(b); } for(long long i=1;i&lt;=n;i++) { cnt[findf(i)]++; } for(long long i=1;i&lt;=n;i++) { ans+=(cnt[i]-1)*cnt[i]/2; } cout&lt;&lt;ans-m&lt;&lt;&quot;
&quot;; return 0;} E. Toward 0学校刚教完概率与期望，我却不会做，是__导致我这样的 看到1e18的数据范围直接被MLE劝退，愣是没有想到其实可以用map，是__导致我这样的！ 骰子只有1-6的点数，所以每次到的值都是可以写作 $⌊ rac{𝑛}{2^𝑖3^𝑗5^𝑘}⌋$ （因为 $⌊ rac{⌊ rac{n}{x}⌋}{y}⌋=⌊ rac{⌊ rac{n}{y}⌋}{x}⌋=⌊ rac{n}{xy}⌋$ ） 所以我们就可以聪明地使用map数组dp，得到以下递推公式： dp_i=min(x+dp_{⌊ rac{n}{a}⌋}, rac{6}{5}(y+i=\sum_{i=2}^{6}dp_{⌊ rac{n}{i}⌋}))123456789101112131415161718192021222324252627282930313233343536373839404142434445#include&lt;bits/stdc++.h&gt;using namespace std;long long n,a,x,y;map&lt;long long,double&gt; dp;int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;a&gt;&gt;x&gt;&gt;y; dp[0]=0; for(long long i=1;i&lt;=n;i*=2) { for(long long j=1;i*j&lt;=n;j*=3) { for(long long k=1;i*j*k&lt;=n;k*=5) { dp[n/(i*j*k)]=0; //先新建可能取到的dp索引对应的dp数组的位置（因为使用map） } } } for(map&lt;long long,double&gt;::iterator i=dp.begin();i!=dp.end();i++) { if(!i-&gt;first) { continue; } double p=x+dp[i-&gt;first/a],q=6.0*y; //p是选择/a的期望，q是选择抛骰子的期望 for(int j=2;j&lt;=6;j++) { q+=dp[i-&gt;first/j]; } q/=5; i-&gt;second=min(p,q); //递推，最小代价 } cout&lt;&lt;fixed&lt;&lt;setprecision(6)&lt;&lt;dp[n]&lt;&lt;&quot;
&quot;; return 0;} F. Transpose非常经典的栈，试问Atcoder，为何E&gt;F。 其实感觉难度不是很大，不知道为什么是绿并F题，但话说我一直都很讨厌这种 (((()))(()) 的题QAQ 同样也是直接模拟，但是首先利用栈来记录这个字符串所有括号的位置和字母是否最终被反转 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667686970717273747576777879808182838485868788#include&lt;bits/stdc++.h&gt;using namespace std;string s;int p[500005]; //用于配对左括弧和右括弧的位置stack&lt;int&gt; st; //用于存储左括弧void output(int x,int y){ if(x&lt;=y) { for(int i=x;i&lt;=y;i++) { if(s[i]=='(') { if(p[i]!=i+1) //如果括号组内不为空 { output(p[i]-1,i+1); //整体翻转输出 } i=p[i]; //跳到下一组 } else { cout&lt;&lt;s[i]; } } } else { for(int i=x;i&gt;=y;i--) { if(s[i]==')') { if(p[i]!=i-1) { output(p[i]+1,i-1); //整体翻转输出 } i=p[i]; //跳到下一组 } else { cout&lt;&lt;s[i]; } } }}int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;s; for(int i=0;i&lt;s.size();i++) { if(s[i]=='(') { st.push(i); } else if(s[i]==')') { p[st.top()]=i; p[i]=st.top(); st.pop(); } else { //如果这个字符在奇数个括号组里，就说明它会被大小写反转,偶数则会被反转回来 if(st.size()&amp;1) { if(s[i]&gt;='a'&amp;&amp;s[i]&lt;='z') { s[i]-='a'-'A'; } else { s[i]-='A'-'a'; } } } } output(0,s.size()-1); cout&lt;&lt;&quot;
&quot;; return 0;} G. Mediator一道被建议评橙的G题（现在是蓝），Atcoder怎么总能水暴力（？ 于是投喂一篇暴力（它甚至不需要吸氧就能过我真的 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758596061626364656667// Let us water a brute force ! #include&lt;bits/stdc++.h&gt;using namespace std;const long long mod=998244353;long long n,q;vector&lt;long long&gt; e[200005];bool t[200005];void geti(long long &amp;op,long long &amp;u,long long &amp;v,long long xl) //如题{ op=1+(((op*(1+xl))%mod)%2); u=1+(((u*(1+xl))%mod)%n); v=1+(((v*(1+xl))%mod)%n);}int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;q; long long xl=0; while(q--) { memset(t,0,sizeof t); long long op,u,v; cin&gt;&gt;op&gt;&gt;u&gt;&gt;v; geti(op,u,v,xl); if(op==1) { e[v].push_back(u); e[u].push_back(v); //存边 continue; } for(long long i:e[u]) //遍历与u相邻的点 { t[i]=1; } bool flag=0; for(long long i:e[v]) { if(t[i]) //判断是否与v相邻 { cout&lt;&lt;i&lt;&lt;&quot;
&quot;; xl=i; flag=1; break; } } if(!flag) //否则输出0 { cout&lt;&lt;0&lt;&lt;&quot;
&quot;; xl=0; } } return 0;} 好吧下面是正解 使用启发式合并。如果两个点有一个共同的邻点，那么有三种可能： u是v的祖父 v是u的祖父 u和v是兄弟 所以依然使用带权并查集进行维护。 123456789101112131415161718192021222324252627282930313233343536373839404142434445464748495051525354555657585960616263646566676869707172737475767778798081828384858687888990919293949596979899100101102103104105106#include&lt;bits/stdc++.h&gt;using namespace std;const long long mod=998244353;long long n,q;vector&lt;long long&gt; e[200005];int f[200005],par[200005],siz[200005];//分别为点i的父亲，点i的根，点i的深度void geti(long long &amp;op,long long &amp;u,long long &amp;v,long long xl){ op=1+(((op*(1+xl))%mod)%2); u=1+(((u*(1+xl))%mod)%n); v=1+(((v*(1+xl))%mod)%n);}void dfs(int x) //遍历并确定每个点的父亲节点{ for(auto i:e[x]) { if(i==f[x]) { continue; } f[i]=x; dfs(i); }}int query(int x,int y){ if(f[x]==f[y]&amp;&amp;f[x]) //如果两点为兄弟节点 { return f[x]; } if(f[f[x]]==y) //x的祖父为y { return f[x]; } if(f[f[y]]==x) //y的祖父为x { return f[y]; } return 0;}int find(int x) //找根{ return x==par[x]?x:par[x]=find(par[x]);}void merge(int x,int y) //合并{ int fx=find(x),fy=find(y); if(fx==fy) { return; } par[fy]=fx; siz[fx]+=siz[fy]; siz[fy]=0;}int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;q; for(int i=1;i&lt;=n;i++) //初始化 { par[i]=i; siz[i]=1; } long long xl=0; while(q--) { long long op,u,v; cin&gt;&gt;op&gt;&gt;u&gt;&gt;v; geti(op,u,v,xl); if(op==1) { if(siz[find(u)]&lt;siz[find(v)]) { swap(u,v); } e[v].push_back(u); e[u].push_back(v); f[v]=u; merge(u,v); dfs(v); continue; } xl=query(u,v); cout&lt;&lt;xl&lt;&lt;&quot;
&quot;; } return 0;} wow写完啦！！！！！ 感谢观看呀

比赛链接 非常难绷地交了6发罚时。。。 题解A. AtCoder Line应该没什么好讲的 1234567891011121314151617181920212223242526272829#include&lt;bits/stdc++.h&gt;using namespace std;int n;int x,y,z;int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;x&gt;&gt;y&gt;&gt;z; if(x&lt;y) { swap(x,y); } if(x&gt;=z&amp;&amp;y&lt;=z) { cout&lt;&lt;&quot;Yes
&quot;; } else { cout&lt;&lt;&quot;No
&quot;; } return 0;} B. Typing又是双指针，典 1234567891011121314151617181920212223242526272829303132#include&lt;bits/stdc++.h&gt;using namespace std;string s,t;int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;s&gt;&gt;t; for(int i=0,j=0;i&lt;t.size();) { while(t[i]!=s[j]&amp;&amp;i&lt;t.size()) { i++; } if(i==t.size()) { break; } cout&lt;&lt;i+1&lt;&lt;&quot; &quot;; i++,j++; } cout&lt;&lt;&quot;
&quot;; return 0;} C. Standing On The Shoulders由于头高一定比肩高高，而肩高综合是一定的，因此只需要按照头高和肩高之差拍序，找到差最大的即可。 123456789101112131415161718192021222324252627282930313233343536373839#include&lt;bits/stdc++.h&gt;using namespace std;long long n;struct node{ int a,b,d;} x[200005];bool cmp(node a,node b){ return a.d&gt;b.d;}int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n; for(long long i=0;i&lt;n;i++) { cin&gt;&gt;x[i].a&gt;&gt;x[i].b; x[i].d=x[i].b-x[i].a; } sort(x,x+n,cmp); long long ans=0; for(long long i=1;i&lt;n;i++) { ans+=x[i].a; } ans+=x[0].b; cout&lt;&lt;ans&lt;&lt;&quot;
&quot;; return 0;} D. Permutation Subsequence主要是赛时非常抽线地想到了滑动窗口并立刻放弃，转头使用了ST表。 Part1. ST表说实话，当我看到还有人用线段树时，我意识到我不是一个人。 思路其实很简单，存一下每个元素的索引。答案即是，每连续 𝑘k 个元素中最大索引与最小索引之差的最小值。 12345678910111213141516171819202122232425262728293031323334353637383940414243444546#include&lt;bits/stdc++.h&gt;using namespace std;int n,k,p;int id[200005];int ans=1e9;int f1[200005][20],f2[200005][20]; int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;k; for(int i=1;i&lt;=n;i++) { cin&gt;&gt;p; id[p]=i; } //ST表板子部分 for(int i=1;i&lt;=n;i++) { f1[i][0]=f2[i][0]=id[i]; } for(int j=1;(1&lt;&lt;j)&lt;=n;j++) { for(int i=1;i+(1&lt;&lt;(j-1))&lt;=n;i++) { f1[i][j]=max(f1[i][j-1],f1[i+(1&lt;&lt;(j-1))][j-1]); f2[i][j]=min(f2[i][j-1],f2[i+(1&lt;&lt;(j-1))][j-1]); } } int s=log2(k); for(int i=1;i+k-1&lt;=n;i++) { ans=min(ans,max(f1[i][s],f1[i+k-1-(1&lt;&lt;s)+1][s])-min(f2[i][s],f2[i+k-1-(1&lt;&lt;s)+1][s])); } cout&lt;&lt;ans&lt;&lt;&quot;
&quot;; return 0;} 跑到了49ms，过肯定是能过的 Part.2 滑动窗口其实思路是一样的，但是用单调队列来维护 12345678910111213141516171819202122232425262728293031323334353637383940414243444546474849505152535455565758#include&lt;bits/stdc++.h&gt;using namespace std;int n,k,p;int id[200005];int ans=1e9;deque&lt;int&gt; mn,mx;int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;n&gt;&gt;k; for(int i=1;i&lt;=n;i++) { cin&gt;&gt;p; id[p]=i; } //滑动窗口板子部分 for(int i=1;i&lt;=n;i++) { //超过k个值了所以这个元素可以丢掉了 while(!mn.empty()&amp;&amp;i-mn.front()&gt;=k) { mn.pop_front(); } while(!mx.empty()&amp;&amp;i-mx.front()&gt;=k) { mx.pop_front(); } //如果放进来的值超过了原来的极值，把原来的极值扔掉 while(!mn.empty()&amp;&amp;id[i]&lt;=id[mn.back()]) { mn.pop_back(); } while(!mx.empty()&amp;&amp;id[i]&gt;=id[mx.back()]) { mx.pop_back(); } //直到不超过原来的极值，把它放在最后面维持单调性 mn.push_back(i); mx.push_back(i); if(i&gt;=k) { ans=min(ans,id[mx.front()]-id[mn.front()]); } } cout&lt;&lt;ans&lt;&lt;&quot;
&quot;; return 0;} 跑到了14ms的绝佳成绩 但其实我觉得这两种方法都可以算正解吧（？ 它们的板子都是黄题。 To Be Continued…

比赛链接 我服了做得太烂了。。。 还差36分变绿，死一会儿。。。 题解A. Maximize?典，暴力枚举即可 1234567891011121314151617181920212223242526272829#include&lt;bits/stdc++.h&gt; using namespace std; int t,x; int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;t; while(t--) { cin&gt;&gt;x; int mx=0,id=0; for(int i=1;i&lt;x;i++) { if(__gcd(x,i)+i&gt;mx) { mx=__gcd(x,i)+i; id=i; } } cout&lt;&lt;id&lt;&lt;&quot;
&quot;; } return 0;} B. Prefiquence双指针，也很典 1234567891011121314151617181920212223242526272829303132333435#include&lt;bits/stdc++.h&gt; using namespace std; int t,n,m;string a,b; int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;t; while(t--) { cin&gt;&gt;n&gt;&gt;m&gt;&gt;a&gt;&gt;b; int cn1=b.size(),cn2=a.size(); int i=0,j=0; while(i&lt;cn1&amp;&amp;j&lt;cn2) { if(a[j]==b[i]) { j++; } if(j==cn2) { break; } i++; } cout&lt;&lt;j&lt;&lt;&quot;
&quot;; } return 0;} C. Assembly via Remainders比较简单的构造，保证每个$a[i-1]&gt;x[i]$即可 12345678910111213141516171819202122232425262728293031323334353637383940#include&lt;bits/stdc++.h&gt; using namespace std; int t;int n;long long x[505],a[505];long long pre; int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;t; while(t--) { cin&gt;&gt;n; for(int i=2;i&lt;=n;i++) { cin&gt;&gt;x[i]; } a[1]=x[2]+1; for(int i=2;i&lt;=n;i++) { a[i]=a[i-1]+x[i]; while(a[i]&lt;=x[i+1]) { a[i]+=a[i-1]; } } for(int i=1;i&lt;=n;i++) { cout&lt;&lt;a[i]&lt;&lt;&quot; &quot;; } cout&lt;&lt;&quot;
&quot;; } return 0;} D. Permutation Game与zhy女士讨论的思路甚至是对的。 大概是一个类似于线性dp的思路，以min(循环节长度, $k$ )为循环，这样循环大小不会超过 $2×10^5$ 1234567891011121314151617181920212223242526272829303132333435363738394041424344454647484950515253545556575859606162#include&lt;bits/stdc++.h&gt;using namespace std;long long t;long long n,k,pb,ps;long long a[200005],p[200005];bool vis[200005];long long score(long long x,long long k){ memset(vis,0,sizeof vis); long long mx=0,sum=0; while(!vis[x]&amp;&amp;k&gt;0) //如果第一个循环节没有循环完并且还没有走k步 { vis[x]=1; mx=max(mx,sum+k*a[x]); //sum+k*a[x]是走到这个点就不动了，与下一层循环里的再走一步再停下进行比较 sum+=a[x]; //走一步 k--; //还剩几步 x=p[x]; //下一个 } return mx;}int main(){ ios::sync_with_stdio(0); cin.tie(0),cout.tie(0); cin&gt;&gt;t; while(t--) { long long n,k,pb,ps; cin&gt;&gt;n&gt;&gt;k&gt;&gt;pb&gt;&gt;ps; for(long long i=1;i&lt;=n;i++) { cin&gt;&gt;p[i]; } for(long long i=1;i&lt;=n;i++) { cin&gt;&gt;a[i]; } long long A=score(pb,k),B=score(ps,k); if(A&gt;B) //比较 { cout&lt;&lt;&quot;Bodya
&quot;; } else if(A&lt;B) { cout&lt;&lt;&quot;Sasha
&quot;; } else { cout&lt;&lt;&quot;Draw
